const msg = $input.first().json.message;
const chatId = msg?.chat?.id;

if (chatId !== 1375806243) {
  return [{ json: { action: 'ignore', reason: 'Wrong chat ID: ' + chatId } }];
}

const text = (msg.text || '').toLowerCase().trim();
const replyTo = msg.reply_to_message?.text || '';

const draftIdMatch = replyTo.match(/Draft ID:\s*([a-f0-9-]+)/);
const draftId = draftIdMatch ? draftIdMatch[1] : null;

if (!draftId) {
  return [{ json: { action: 'ignore', reason: 'Not a reply to a draft message' } }];
}

const isApproval = ['go', 'approved', 'approve'].includes(text);

return [{
  json: {
    action: isApproval ? 'approve' : 'feedback',
    draftId,
    feedback: isApproval ? null : msg.text
  }
}];

const response = $input.first().json;
const content = response.content?.[0]?.text;
if (!content) throw new Error('No content in Claude response');

let parsed;
try {
  const cleaned = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Failed to parse: ' + e.message);
}

const originalDraft = $('Fetch Original Draft').first().json;
const postType = Array.isArray(originalDraft) ? originalDraft[0]?.post_type : originalDraft?.post_type;

return [{
  json: {
    ...parsed,
    post_type: postType || 'value-led',
    status: 'pending_approval',
    draftId: $('Parse Reply').first().json.draftId
  }
}];

